question:
What does the following TypeScript code do?

function padLeft(value: string, padding: string | number): string {
  if (typeof padding === 'number') {
    return ' '.repeat(padding) + value;
  }
  return padding + value;
}

What is the output type inferred by TypeScript for this function?

function throwError(message: string): never {
  throw new Error(message);
}

What will the following TypeScript code produce?

interface Animal { name: string; }
interface Dog extends Animal { breed: string; }

const myDog: Dog = { name: 'Rex', breed: 'Labrador' };
console.log(myDog.name);

What is the type of 'output' in the following code?

function identity<T>(arg: T): T {
  return arg;
}
const output = identity('hello');

What is a TypeScript 'enum' and what does the following code output at runtime?

enum Direction { Up = 1, Down, Left, Right }
console.log(Direction.Left);

What does the following TypeScript code demonstrate?

type Shape =
  | { kind: 'circle'; radius: number }
  | { kind: 'square'; side: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case 'circle': return Math.PI * shape.radius ** 2;
    case 'square': return shape.side ** 2;
  }
}

What does a user-defined type guard function with the return type 'arg is Type' do?

function isString(arg: unknown): arg is string {
  return typeof arg === 'string';
}

What is the 'ReturnType<T>' utility type?

function greet(name: string): string { return `Hello ${name}`; }
type R = ReturnType<typeof greet>;

What does the following TypeScript code demonstrate and will it compile?

class Animal {
  constructor(private name: string) {}
  speak(): string { return `${this.name} makes a noise.`; }
}
const a = new Animal('Dog');
console.log(a.name);

What does the following code output and why?

type Flatten<T> = T extends Array<infer Item> ? Item : T;
type Str = Flatten<string[]>;
type Num = Flatten<number>;

What does the 'satisfies' operator (introduced in TypeScript 4.9) do?

const palette = {
  red: [255, 0, 0],
  green: '#00ff00',
} satisfies Record<string, string | number[]>;
